insert into 
	movmov_payment_histories

(
	pay_id
	, pay_status_id
	, user_id
	, item_no
	, option_no
	, pay_amount
	, pay_date
	, pt_use_amount
	, pt_earn_amount
	, addr_id
	, pay_method_id
	, request
	, item_quantity
)

values
(
	seq_pay_id.NEXTVAL
	, #{payStatusId}
	, #{user.id}
	, #{item.no}
	, #{option.no}
	, #{payAmount}
	, SYSDATE
	, #{ptUseAmount}
	, #{ptEarnAmount}
	, #{address.id}
	, #{payMethodId}
	, #{request}
	, #{itemQuantity}
)

