select select pay_id as payId , pay_status_id as payStatusId , user_id as "user.id" , item_no as "item.no" , option_no as "option.no" , pay_amount as payAmount , pay_date as payDate , pt_use_amount as ptUseAmount , pt_earn_amount as ptEarnAmount , addr_id as "address.id" , pay_method_id as payMethodId , request as request , item_quantity as itemQuantity
from movmov_payment_histories
where pay_id = #{id}

select pay_id as payId , pay_status_id as payStatusId , user_id as "user.id" , item_no as "item.no" , option_no as "option.no" , pay_amount as payAmount , pay_date as payDate , pt_use_amount as ptUseAmount , pt_earn_amount as ptEarnAmount , addr_id as "address.id" , pay_method_id as payMethodId , request as request , item_quantity as itemQuantity
from movmov_payment_histories
where user_id = #{user.id}

